```class Solution {
public:
    vector<int> separateDigits(vector<int>& nums) {
        vector<int> answer;
        for (int num : nums) {
            string strNum = to_string(num);
            vector<int> digits = split(strNum, '0');
            answer.insert(answer.end(), digits.begin(), digits.end());
        }
        return answer;
    }

private:
    vector<int> split(string str, char delimiter) {
        vector<int> result;
        size_t start = 0;
        while ((start = str.find(delimiter, start)) {
            result.push_back(stoi(substr(str, start, start + 1)));
            start += delimiter.length();
        }
        result.push_back(stoi(substr(str, start, str.length()));
        return result;
    }
};
